  await ensureSchema(db);
  const doc = { createdAt: new Date(), ...data };
  if (doc.preferredPaymentMethod !== undefined && !VALID_PAYMENT_METHODS.includes(doc.preferredPaymentMethod)) {
    throw new Error(`Invalid preferredPaymentMethod: ${doc.preferredPaymentMethod}`);
